import{_ as a,o as n,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"34. Shift Allowance","description":"","frontmatter":{"title":"34. Shift Allowance","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/34-shift-allowance.md","filePath":"ebas/nurses-midwives/allowances/34-shift-allowance.md"}'),o={name:"ebas/nurses-midwives/allowances/34-shift-allowance.md"};function i(r,e,p,l,h,d){return n(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_34-shift-allowance" tabindex="-1">34. Shift Allowance <a class="header-anchor" href="#_34-shift-allowance" aria-label="Permalink to &quot;34. Shift Allowance&quot;">​</a></h1><p>This clause does not apply to a DON or Deputy DON.</p><p><strong>34.1</strong> Definitions</p><p>In this clause 34:</p><p><strong>(a)</strong> Morning shift means any shift that commences between 6:00 p.m. and 6:30 a.m.</p><p><strong>(b)</strong> Afternoon shift means any shift that finishes between 6:00 p.m. and 8 a.m.</p><p><strong>(c)</strong> Night shift means any shift that finishes on the day after commencing duty or commences after midnight and before 5.00 a.m.</p><p><strong>(d)</strong> Sunday night shift means a shift worked by a full-time or part-time Employee that commences on Sunday and concludes on Monday.</p><p><strong>34.2</strong> Application</p><p>Where a shift meets more than one definition as set out at clause 34.1, the Employee will be paid one shift allowance only, with the higher shift allowance applying where the rates differ.</p><p><strong>34.3</strong> Allowances</p><p>In addition to any other rates prescribed elsewhere in this Agreement, the Employee will receive the following allowances where an Employee works:</p><p><strong>(a)</strong> A Morning Shift: an amount set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> per rostered period of duty;</p><p><strong>(b)</strong> An Afternoon Shift: an amount set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> per rostered period of duty;</p><p><strong>(c)</strong> A Night Shift:</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> per period of duty;</p><p><strong>(ii)</strong> In the case of an Employee who is not a casual Employee until 15 May 2025, the rate at (c)(i) above as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>; or</p><p><strong>(iii)</strong> In the case of an Employee who is not a casual Employee from 15 May 2025:</p><p><strong>(A)</strong> the rate at (c)(i) above plus 12.5% for a Night Shift commencing on a Monday, Tuesday, Wednesday or Thursday as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>;</p><p><strong>(B)</strong> the rate at (c)(i) above plus 25% for a Night Shift commencing on a Friday or Saturday as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>; or</p><p><strong>(C)</strong> the Sunday Night shift rate in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> plus 12.5% for a Sunday Night Shift.</p>',21)])])}const m=a(o,[["render",i]]);export{f as __pageData,m as default};
